import numpy as np

def algo(initial_population, individual_upper, individual_lower, objective_function):
    population = initial_population
    best_solution = population[np.argmin([objective_function(ind) for ind in population])]
    evaluation_count = len(population)

    while evaluation_count < 30000:
        fitness = np.array([objective_function(ind) for ind in population])
        groups = {}
        for i in range(len(population)):
            group_key = round(fitness[i], 2)
            if group_key not in groups:
                groups[group_key] = []
            groups[group_key].append(population[i])

        for group in groups.values():
            if len(group) > 1:
                group_center = np.mean(group, axis=0)
                for i in range(len(group)):
                    direction = np.random.uniform(-1, 1, size=group[i].shape[0])
                    group[i] = np.clip(group_center + direction * np.random.rand(), individual_lower, individual_upper)

        for i in range(len(population)):
            if np.random.rand() < 0.2:
                random_vector = np.random.uniform(individual_lower, individual_upper, size=population[i].shape[0])
                population[i] += 0.1 * (random_vector - population[i])
                population[i] = np.clip(population[i], individual_lower, individual_upper)

        new_fitness = np.array([objective_function(ind) for ind in population])
        better_indices = new_fitness < fitness
        population[better_indices] = population[better_indices]
        fitness[better_indices] = new_fitness[better_indices]

        current_best_index = np.argmin(fitness)
        if fitness[current_best_index] < objective_function(best_solution):
            best_solution = population[current_best_index]

        evaluation_count += len(population)

    return best_solution
